{
    "level": "A1–A2",
    "intro": "In this topic you will learn <strong>zero article</strong> - when in English <strong>the article is not needed</strong> before noun.",
    "rules": [
        {
            "label": "Abstractions",
            "color": "emerald",
            "text": "<strong>Abstract concepts</strong> - general meaning:",
            "example": "Love is important. / I like music."
        },
        {
            "label": "Plural",
            "color": "blue",
            "text": "<strong>Plural in general</strong> - all representatives:",
            "example": "Dogs are loyal. I like cats. What is a zero article?"
        },
        {
            "label": "Імена",
            "color": "amber",
            "text": "<strong>Власні назви</strong> — країни, міста, імена:",
            "example": "Ukraine, London, John"
        }
    ]
}

{
    "title": "1. Що таке нульовий артикль?",
    "intro": "A zero article is the absence of an article before a noun:",
    "items": [
        {
            "label": "Ø Article",
            "title": "No article",
            "subtitle": "A noun without a/an or the is zero article"
        },
        {
            "label": "Common",
            "title": "Very common",
            "subtitle": "In English there are many cases when an article is not needed"
        },
        {
            "label": "Rules",
            "title": "There are rules",
            "subtitle": "Certain categories of words are always without article"
        }
    ]
}

{
    "title": "2. Abstract and uncountable nouns",
    "sections": [
        {
            "label": "Abstract concepts",
            "color": "emerald",
            "description": "<strong>Abstract nouns</strong> in the general sense — without an article.",
            "examples": [
                {
                    "en": "Love is important.",
                    "ua": "Love is important."
                },
                {
                    "en": "Happiness makes life better.",
                    "ua": " better."
                },
                {
                    "en": "Knowledge is power.",
                    "ua": "Knowledge is power."
                },
                {
                    "en": "Freedom is valuable.",
                    "ua": "Freedom is valuable."
                }
            ]
        },
        {
            "label": "Uncountable in general",
            "color": "sky",
            "description": "<strong>Uncountable nouns</strong> in general - without article.",
            "examples": [
                {
                    "en": "I love music.",
                    "ua": "I love music. (music in general)"
                },
                {
                    "en": "Water is essential.",
                    "ua": "Water is essential. (water in general)"
                },
                {
                    "en": "Money can't buy happiness.",
                    "ua": "Money can't buy happiness."
                },
                {
                    "en": "Information is everywhere.",
                    "ua": "Information is everywhere."
                }
            ]
        },
        {
            "label": "Attention!",
            "color": "amber",
            "description": "If it is about <strong>specific</strong> portion, the article <strong>the</strong> is required.",
            "examples": [
                {
                    "en": "I love music. (in general)",
                    "ua": "I love music."
                },
                {
                    "en": "I love the music in this film. (specific)",
                    "ua": "I like the music from this movie."
                }
            ],
            "note": "📌 The general concept is Ø, the specific concept is the."
        }
    ]
}

{
    "title": "3. Plural in the general sense",
    "sections": [
        {
            "label": "General statements",
            "color": "blue",
            "description": "When we talk about <strong>all members of the group</strong> - without an article.",
            "examples": [
                {
                    "en": "Dogs are loyal animals.",
                    "ua": "Dogs are loyal animals. (all dogs)"
                },
                {
                    "en": "Cats like to sleep.",
                    "ua": "Cats like to sleep. (cats in general)"
                },
                {
                    "en": "Books are expensive.",
                    "ua": "Books are expensive. (books in general)"
                },
                {
                    "en": "Children need love.",
                    "ua": "Children need love."
                }
            ]
        },
        {
            "label": "Likes and hobbies",
            "color": "emerald",
            "description": "With verbs <strong>like, love, hate</strong> about general things - without article.",
            "examples": [
                {
                    "en": "I like apples.",
                    "ua": "I i love apples (apples in general)"
                },
                {
                    "en": "She loves flowers.",
                    "ua": "She loves flowers."
                },
                {
                    "en": "He hates spiders.",
                    "ua": "He hates spiders."
                },
                {
                    "en": "We enjoy movies.",
                    "ua": " films."
                }
            ]
        },
        {
            "label": "Plural professions",
            "color": "sky",
            "description": "The plural of professions in general is without an article.",
            "examples": [
                {
                    "en": "Teachers work hard.",
                    "ua": "Teachers work hard."
                },
                {
                    "en": "Doctors save lives.",
                    "ua": "Doctors save lives."
                },
                {
                    "en": "Engineers solve problems.",
                    "ua": "Engineers solve problems."
                }
            ]
        }
    ]
}

{
    "title": "4. Proper names (names, countries, cities)",
    "sections": [
        {
            "label": "Names of people",
            "color": "purple",
            "description": "<strong>First names and surnames</strong> - without an article.",
            "examples": [
                {
                    "en": "John is my friend.",
                    "ua": "John is my friend."
                },
                {
                    "en": "Maria works here.",
                    "ua": "Maria works here."
                },
                {
                    "en": "Mr. Smith called yesterday.",
                    "ua": "Mr. Smith called yesterday."
                },
                {
                    "en": "President Zelenskyy spoke today.",
                    "ua": "President Zelenskyy spoke today."
                }
            ]
        },
        {
            "label": "Countries and cities",
            "color": "emerald",
            "description": "<strong>Most countries and cities</strong> — no article.",
            "examples": [
                {
                    "en": "Ukraine is beautiful.",
                    "ua": "Ukraine is beautiful."
                },
                {
                    "en": "I live in Kyiv.",
                    "ua": "I live in Kyiv."
                },
                {
                    "en": "France is in Europe.",
                    "ua": "France in Europe."
                },
                {
                    "en": "London is a big city.",
                    "ua": "London is a big city."
                }
            ]
        },
        {
            "label": "Exceptions with the article THE",
            "color": "rose",
            "description": "Some countries <strong>always with the</strong> (plural or union):",
            "examples": [
                {
                    "en": "the USA, the United States",
                    "ua": "USA, the United States"
                },
                {
                    "en": "the UK, the United Kingdom",
                    "ua": "Great Britain, the United Kingdom"
                },
                {
                    "en": "the Netherlands",
                    "ua": "Netherlands"
                },
                {
                    "en": "the Philippines",
                    "ua": "Philippines"
                }
            ],
            "note": "⚠️ These exceptions must be remembered!"
        }
    ]
}

{
    "title": "5. Geographical objects without an article",
    "sections": [
        {
            "label": "Continents",
            "color": "sky",
            "description": "<strong>Continent names</strong> — without an article.",
            "examples": [
                {
                    "en": "Europe, Asia, Africa",
                    "ua": "Europe, Asia, Africa"
                },
                {
                    "en": "North America, South America",
                    "ua": "North America, South America"
                },
                {
                    "en": "Australia is a continent.",
                    "ua": "Australia is a continent."
                }
            ]
        },
        {
            "label": "Mountains (individual peaks)",
            "color": "emerald",
            "description": "<strong>Individual mountains</strong> - no article (but mountain systems - with the).",
            "examples": [
                {
                    "en": "Mount Everest",
                    "ua": "Mount Everest"
                },
                {
                    "en": "Hoverla is the highest peak in Ukraine.",
                    "ua": "Hoverla is the highest peak in Ukraine."
                },
                {
                    "en": "BUT: the Alps, the Carpathians",
                    "ua": "BUT: the Alps, the Carpathians (systems — with the)"
                }
            ]
        },
        {
            "label": "Lakes (with Lake)",
            "color": "blue",
            "description": "If <strong>Lake + name</strong> — no article.",
            "examples": [
                {
                    "en": "Lake Baikal",
                    "ua": "Lake Baikal"
                },
                {
                    "en": "Lake Superior",
                    "ua": "Osero Superior"
                },
                {
                    "en": "BUT: the Baikal (without the word Lake)",
                    "ua": "BUT: without the word Lake, the"
                }
            ]
        }
    ]
}

{
    "title": "6 is needed. Regular expressions without an article",
    "sections": [
        {
            "label": "Places (at/to + place)",
            "color": "amber",
            "description": "In regular expressions with <strong>places</strong> — without an article.",
            "examples": [
                {
                    "en": "at home, at work, at school",
                    "ua": "at home, at work, at school"
                },
                {
                    "en": "go to bed, go to work, go to church",
                    "ua": "go to bed, go to work, go to church"
                },
                {
                    "en": "in hospital (UK), in prison",
                    "ua": "at university, at college"
                },
                {
                    "en": "at university, at college",
                    "ua": "at university, in colleges"
                }
            ]
        },
        {
            "label": "Transport (by + transport)",
            "color": "sky",
            "description": "With the preposition <strong>by</strong> — without an article.",
            "examples": [
                {
                    "en": "by car, by bus, by train",
                    "ua": "by car, bus, train"
                },
                {
                    "en": "by plane, by boat, by bike",
                    "ua": "by plane, boat, bicycle"
                },
                {
                    "en": "BUT: on the bus, in the car",
                    "ua": "BUT: with on/in requires an article"
                }
            ]
        },
        {
            "label": "Food (meals)",
            "color": "emerald",
            "description": "Names of <strong>meals</strong> — without article.",
            "examples": [
                {
                    "en": "have breakfast, have lunch, have dinner",
                    "ua": "breakfast, have lunch, have dinner"
                },
                {
                    "en": "What's for dinner?",
                    "ua": "What's for dinner?"
                },
                {
                    "en": "after breakfast",
                    "ua": "after breakfast"
                },
                {
                    "en": "BUT: the dinner was delicious",
                    "ua": "BUT: the specific dinner is from the"
                }
            ]
        }
    ]
}

{
    "title": "7. Sports, languages, subjects",
    "sections": [
        {
            "label": "Sports",
            "color": "purple",
            "description": "<strong>Names of sports games</strong> — no article.",
            "examples": [
                {
                    "en": "play football, play tennis",
                    "ua": "play football, play tennis"
                },
                {
                    "en": "I like basketball.",
                    "ua": "I like basketball."
                },
                {
                    "en": "She plays volleyball.",
                    "ua": "She plays volleyball."
                }
            ]
        },
        {
            "label": "Languages",
            "color": "blue",
            "description": "<strong>Language names</strong> — without article.",
            "examples": [
                {
                    "en": "I speak English.",
                    "ua": "I speak in English."
                },
                {
                    "en": "She studies Ukrainian.",
                    "ua": "She studies Ukrainian."
                },
                {
                    "en": "French is beautiful.",
                    "ua": "French is beautiful."
                },
                {
                    "en": "BUT: the English language",
                    "ua": "BUT: with the word language the"
                }
            ]
        },
        {
            "label": "Educational subjects",
            "color": "emerald",
            "description": "<strong>School subjects</strong> — no article.",
            "examples": [
                {
                    "en": "I like mathematics.",
                    "ua": "I like mathematics."
                },
                {
                    "en": "History is interesting.",
                    "ua": "History interesting."
                },
                {
                    "en": "She studies biology.",
                    "ua": "She studies biology."
                }
            ]
        }
    ]
}

{
    "title": "8. Time of day and holidays",
    "sections": [
        {
            "label": "Days of the week, months, holidays",
            "color": "rose",
            "description": "<strong>Days, months and holidays</strong> — no article.",
            "examples": [
                {
                    "en": "Monday, Tuesday, Wednesday",
                    "ua": "Monday, Tuesday, Wednesday"
                },
                {
                    "en": "January, February, March",
                    "ua": "January, February, March"
                },
                {
                    "en": "Christmas, Easter, New Year",
                    "ua": "Christmas, Easter, New Year"
                },
                {
                    "en": "on Monday, in January",
                    "ua": " January"
                }
            ]
        },
        {
            "label": "Seasons",
            "color": "amber",
            "description": "<strong>Seasons</strong> - usually without an article (but there can be a variation).",
            "examples": [
                {
                    "en": "Spring is beautiful.",
                    "ua": "Spring is beautiful."
                },
                {
                    "en": "I like summer.",
                    "ua": "I love summer."
                },
                {
                    "en": "in autumn, in winter",
                    "ua": "autumn, winter"
                },
                {
                    "en": "BUT: the summer of 2023",
                    "ua": "BUT: a specific summer can be from the"
                }
            ]
        },
        {
            "label": "Parts of the day (in general)",
            "color": "sky",
            "description": "In some expressions — without an article.",
            "examples": [
                {
                    "en": "at night (without the!)[[[CODX_19]]]at night (without the!)",
                    "ua": "вночі (без the!)"
                },
                {
                    "en": "by day, by night",
                    "ua": "by day, by night"
                },
                {
                    "en": "BUT: in the morning, in the afternoon",
                    "ua": " the)"
                }
            ]
        }
    ]
}

{
    "title": "9. Comparison table: Ø vs The",
    "intro": "Main cases when the article is NOT needed:",
    "rows": [
        {
            "en": "General / abstract",
            "ua": "General / abstract",
            "note": "Ø: Love is important. / Music is great."
        },
        {
            "en": "Plural in general",
            "ua": "Plural in general",
            "note": "Ø: Dogs are loyal. Books are expensive. Smith"
        },
        {
            "en": "Countries, cities",
            "ua": "Країни, міста",
            "note": "Ø: Ukraine, London (but: the USA, the UK)"
        },
        {
            "en": "Names",
            "ua": "Імена",
            "note": "Ø: John, Maria, Mr. Smith"
        },
        {
            "en": "Fixed expressions",
            "ua": "Regular expressions",
            "note": "Ø: at home, by car, have breakfast"
        },
        {
            "en": "Sports, languages",
            "ua": "Sports, languages",
            "note": "Ø: play football, speak English"
        }
    ],
    "warning": "📌 If something is <strong>concrete</strong> or <strong>marked</strong> — we use <strong>the</strong>!"
}

{
    "title": "10. Typical mistakes",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "Article before abstractions.",
            "wrong": "The love is important.",
            "right": "​​​​ <span class="font-mono">Love is important.</span>"
        },
        {
            "label": "Error 2",
            "color": "amber",
            "title": "Article before I live in the Ukraine. loyal.",
            "wrong": "I live in the Ukraine.",
            "right": "✅ <span class="font-mono">I live in Ukraine.</span>"
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Артикль перед множиною в загальному.",
            "wrong": "The dogs are loyal.",
            "right": " ✅ <span class="font-mono">Dogs are loyal. (all dogs in general)</span>"
        },
        {
            "label": "Error 4",
            "color": "purple",
            "title": "Article in fixed expressions.",
            "wrong": "go to the bed, at the home",
            "right": " ✅ <span class="font-mono">go to bed, at home</span>"
        }
    ]
}

{
    "title": "12. Practice",
    "select_title": "Exercise 1. Do you need an article?",
    "select_intro": "Determine whether an article is needed in these sentences.",
    "selects": [
        {
            "label": "___ love is important. (Ø / the)",
            "prompt": "Do you need an article?"
        },
        {
            "label": "I live in ___ Ukraine. (Ø / the)",
            "prompt": "Need an article?"
        },
        {
            "label": "___ dogs are loyal. (Ø / the)",
            "prompt": "Need an article?"
        },
        {
            "label": "I speak ___ English. (Ø/the) __ bus. an error with the article.",
            "prompt": "Потрібен артикль?"
        }
    ],
    "options": [
        "Ø (без артикля)",
        "the"
    ],
    "input_title": "Вправа 2. Заповни пропуски",
    "input_intro": "Напиши Ø (без артикля) або the.",
    "inputs": [
        {
            "before": "I go to ___ work by ___ bus.",
            "after": "→"
        },
        {
            "before": "___ freedom is important.",
            "after": "→"
        },
        {
            "before": "She lives in ___ USA.",
            "after": "→"
        }
    ],
    "rephrase_title": "Вправа 3. Виправ помилки",
    "rephrase_intro": "Знайди і виправ помилку з артиклем.",
    "rephrase": [
        {
            "example_label": "Example:",
            "example_original": "The love is beautiful.",
            "example_target": "Love is beautiful."
        },
        {
            "original": "1. I live in the Ukraine.",
            "placeholder": "Fix the error"
        },
        {
            "original": "2. The dogs are loyal animals.",
            "placeholder": "Correct the error"
        }
    ]
}

{
    "title": "Other pages from the category Nouns, articles and number",
    "items": [
        {
            "label": "Zero Article — Zero article",
            "current": true
        },
        {
            "label": "Articles A / An / The — Articles",
            "current": false
        },
        {
            "label": "Plural Nouns - Plurality of nouns",
            "current": false
        },
        {
            "label": "Countable vs Uncountable - Countable / uncountable",
            "current": false
        }
    ]
}
